class Custom_User_Authentication {
    
    private $table_name;
    
    public function __construct() {
        global $wpdb;
        $this->table_name = $wpdb->prefix . 'custom_users';
        
        register_activation_hook(__FILE__, array($this, 'activate'));
        add_action('init', array($this, 'init'));
        add_shortcode('custom_register', array($this, 'registration_form'));
        add_shortcode('custom_login', array($this, 'login_form'));
        add_action('wp_ajax_nopriv_custom_register', array($this, 'handle_registration'));
        add_action('wp_ajax_nopriv_custom_login', array($this, 'handle_login'));
        add_action('wp_ajax_custom_logout', array($this, 'handle_logout'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_scripts'));
    }
    
    public function activate() {
        global $wpdb;
        
        $charset_collate = $wpdb->get_charset_collate();
        
        $sql = "CREATE TABLE IF NOT EXISTS {$this->table_name} (
            id mediumint(9) NOT NULL AUTO_INCREMENT,
            username varchar(60) NOT NULL,
            email varchar(100) NOT NULL,
            password varchar(255) NOT NULL,
            created_at datetime DEFAULT CURRENT_TIMESTAMP,
            last_login datetime DEFAULT NULL,
            PRIMARY KEY  (id),
            UNIQUE KEY username (username),
            UNIQUE KEY email (email)
        ) $charset_collate;";
        
        require_once(ABSPATH . 'wp-admin/includes/upgrade.php');
        dbDelta($sql);
    }
    
    public function init() {
        if (!session_id()) {
            session_start();
        }
    }
    
    public function enqueue_scripts() {
        wp_enqueue_script('jquery');
        wp_enqueue_script('custom-auth-js', plugin_dir_url(__FILE__) . 'custom-auth.js', array('jquery'), '1.0', true);
        wp_localize_script('custom-auth-js', 'customAuth', array(
            'ajax_url' => admin_url('admin-ajax.php'),
            'nonce' => wp_create_nonce('custom_auth_nonce')
        ));
        wp_enqueue_style('custom-auth-css', plugin_dir_url(__FILE__) . 'custom-auth.css', array(), '1.0');
    }
    
    public function registration_form() {
        if ($this->is_user_logged_in()) {
            return '<p>You are already logged in.</p>';
        }
        
        ob_start();
        ?>
        <div class="custom-auth-form">
            <h2>Register</h2>
            <form id="custom-register-form">
                <div class="form-group">
                    <label for="reg_username">Username:</label>
                    <input type="text" id="reg_username" name="username" required>
                </div>
                <div class="form-group">
                    <label for="reg_email">Email:</label>
                    <input type="email" id="reg_email" name="email" required>
                </div>
                <div class="form-group">
                    <label for="reg_password">Password:</label>
                    <input type="password" id="reg_password" name="password" required>
                </div>
                <div class="form-group">
                    <label for="reg_confirm_password">Confirm Password:</label>
                    <input type="password" id="reg_confirm_password" name="confirm_password" required>
                </div>
                <div class="form-group">
                    <button type="submit">Register</button>
                </div>
                <div id="register-message"></div>
            </form>
        </div>
        <?php
        return ob_get_clean();
    }
    
    public function login_form() {
        if ($this->is_user_logged_in()) {
            $user = $this->get_current_user();
            ob_start();
            ?>
            <div class="custom-auth-form">
                <p>Welcome, <?php echo esc_html($user['username']); ?>!</p>
                <button id="custom-logout-btn">Logout</button>
            </div>
            <?php
            return ob_get_clean();
        }
        
        ob_start();
        ?>
        <div class="custom-auth-form">
            <h2>Login</h2>
            <form id="custom-login-form">
                <div class="form-group">
                    <label for="login_username">Username or Email:</label>
                    <input type="text" id="login_username" name="username" required>
                </div>
                <div class="form-group">
                    <label for="login_password">Password:</label>
                    <input type="password" id="login_password" name="password" required>
                </div>
                <div class="form-group">
                    <button type="submit">Login</button>
                </div>
                <div id="login-message"></div>
            </form>
        </div>
        <?php
        return ob_get_clean();
    }
    
    public function handle_registration() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        $username = sanitize_text_field($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = $_POST['password'];
        $confirm_password = $_POST['confirm_password'];
        
        if (empty($username) || empty($email) || empty($password)) {
            wp_send_json_error(array('message' => 'All fields are required.'));
        }
        
        if (!is_email($email)) {
            wp_send_json_error(array('message' => 'Invalid email address.'));
        }
        
        if (strlen($password) < 6) {
            wp_send_json_error(array('message' => 'Password must be at least 6 characters long.'));
        }
        
        if ($password !== $confirm_password) {
            wp_send_json_error(array('message' => 'Passwords do not match.'));
        }
        
        if ($this->user_exists($username, $email)) {
            wp_send_json_error(array('message' => 'Username or email already exists.'));
        }
        
        $hashed_password = $this->hash_password($password);
        
        global $wpdb;
        $result = $wpdb->insert(
            $this->table_name,
            array(
                'username' => $username,
                'email' => $email,
                'password' => $hashed_password
            ),
            array('%s', '%s', '%s')
        );
        
        if ($result) {
            wp_send_json_success(array('message' => 'Registration successful! You can now login.'));
        } else {
            wp_send_json_error(array('message' => 'Registration failed. Please try again.'));
        }
    }
    
    public function handle_login() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        $username = sanitize_text_field($_POST['username']);
        $password = $_POST['password'];
        
        if (empty($username) || empty($password)) {
            wp_send_json_error(array('message' => 'All fields are required.'));
        }
        
        $user = $this->get_user_by_username_or_email($username);
        
        if (!$user) {
            wp_send_json_error(array('message' => 'Invalid username or password.'));
        }
        
        if ($this->verify_password($password, $user->password)) {
            $_SESSION['custom_user_id'] = $user->id;
            $_SESSION['custom_username'] = $user->username;
            
            global $wpdb;
            $wpdb->update(
                $this->table_name,
                array('last_login' => current_time('mysql')),
                array('id' => $user->id),
                array('%s'),
                array('%d')
            );
            
            wp_send_json_success(array('message' => 'Login successful!', 'redirect' => home_url()));
        } else {
            wp_send_json_error(array('message' => 'Invalid username or password.'));
        }
    }
    
    public function handle_logout() {
        check_ajax_referer('custom_auth_nonce', 'nonce');
        
        unset($_SESSION['custom_user_id']);
        unset($_SESSION['custom_username']);
        session_destroy();
        
        wp_send_json_success(array('message' => 'Logged out successfully.', 'redirect' => home_url()));
    }
    
    private function hash_password($password) {
        return password_hash($password, PASSWORD_BCRYPT, array('cost' => 12));
    }
    
    private function verify_password($password, $hash) {
        return password_verify($password, $hash);
    }
    
    private function user_exists($username, $email) {
        global $wpdb;
        $count = $wpdb->get_var($wpdb->prepare(
            "SELECT COUNT(*) FROM {$this->table_name} WHERE username = %s OR email = %s",
            $username,
            $email
        ));
        return $count > 0;
    }
    
    private function get_user_by_username_or_email($username) {
        global $wpdb;
        return $wpdb->get_row($wpdb->prepare(
            "SELECT * FROM {$this->table_name} WHERE username = %s OR email = %s",
            $username,
            $username
        ));
    }
    
    public function is_user_logged_in() {
        return isset($_SESSION['custom_user_id']) && !empty($_SESSION['custom_user_id']);
    }
    
    public function get_current_user() {
        if (!$this->is_user_logged_in()) {
            return null;
        }
        
        global $wpdb;
        return $wpdb->get_row($wpdb->prepare(
            "SELECT id, username, email, created_at, last_login FROM {$this->table_name} WHERE id = %d",
            $_SESSION['custom_user_id']
        ), ARRAY_A);
    }
}

new Custom_User_Authentication();